ValidationRule.errorConditionFormula:
AND(
    ISPICKVAL(leaseworks__Status__c, 'Delivered'),
    pro_Lease_Documentation_Approval_per__c != 1,
    NOT( 
        OR(
            AND($User.FirstName = "Alan", $User.LastName = "Buckley"),
            AND($User.FirstName = "Claudia", $User.LastName = "Luppino")
        )
    )
)
